import React, { useState, useEffect } from 'react';
import { Users, Truck, AlertOctagon, LocateFixed, Activity, CheckCircle2 } from 'lucide-react';
import { getReps } from '../api';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import L from 'leaflet';

// Fix Leaflet marker icon issue
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
    iconRetinaUrl: require('leaflet/dist/images/marker-icon-2x.png'),
    iconUrl: require('leaflet/dist/images/marker-icon.png'),
    shadowUrl: require('leaflet/dist/images/marker-shadow.png'),
});

const StatCard = ({ title, value, icon: Icon, color, trend }) => (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 flex items-start justify-between">
        <div>
            <p className="text-sm font-medium text-gray-500 mb-1">{title}</p>
            <h3 className="text-3xl font-bold text-gray-800">{value}</h3>
            {trend && <p className="text-xs text-gray-400 mt-2">{trend}</p>}
        </div>
        <div className={`p-4 rounded-full ${color}`}>
            <Icon className="w-6 h-6" />
        </div>
    </div>
);

const RepCard = ({ rep }) => {
    // Generate a mock status based on the mock data logic usually run
    const status = rep.is_active ? 'Active' : 'Inactive';
    const statusColor = rep.is_active ? 'text-green-600 bg-green-50' : 'text-gray-500 bg-gray-50';
    const fraudScore = Math.floor(Math.random() * 40); // Mock score for visually showing UI
    let fsColor = 'text-green-500';
    if (fraudScore > 30) fsColor = 'text-yellow-500';
    if (fraudScore > 70) fsColor = 'text-red-500';

    return (
        <div className="bg-white border flex flex-col justify-between border-gray-200 rounded-lg p-4 hover:shadow-md transition-shadow">
            <div className="flex justify-between items-start mb-4">
                <div className="flex items-center space-x-3">
                    {rep.photo ? (
                        <img 
                            src={rep.photo} 
                            alt={rep.name}
                            className="w-10 h-10 rounded-full object-cover border-2 border-blue-300"
                        />
                    ) : (
                        <div className="w-10 h-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-700 font-bold">
                            {rep.name.charAt(0)}
                        </div>
                    )}
                    <div>
                        <h4 className="font-semibold text-gray-800">{rep.name}</h4>
                        <p className="text-xs text-gray-500">{rep.email}</p>
                    </div>
                </div>
                <span className={`px-2 py-1 rounded text-xs font-semibold ${statusColor}`}>
                    {status}
                </span>
            </div>

            <div className="space-y-3 mt-4">
                <div className="flex justify-between text-sm">
                    <span className="text-gray-500 flex items-center"><Activity className="w-4 h-4 mr-2" /> Fraud Score</span>
                    <span className={`font-semibold ${fsColor}`}>{fraudScore}/100</span>
                </div>
                <div className="flex justify-between text-sm">
                    <span className="text-gray-500 flex items-center"><LocateFixed className="w-4 h-4 mr-2" /> Today's Visits</span>
                    <span className="font-semibold text-gray-700">{Math.floor(Math.random() * 8)}</span>
                </div>
            </div>
        </div>
    );
};


const OverviewTab = () => {
    const [reps, setReps] = useState([]);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchDashboardData = async () => {
            try {
                const repData = await getReps();
                setReps(repData.data || []);
            } catch (error) {
                console.error("Failed fetching data", error);
            } finally {
                setLoading(false);
            }
        };

        fetchDashboardData();
    }, []);

    // Mock map data for demo based on retrieved reps or default values
    const mapData = reps.length > 0 ? reps.map((r, i) => ({
        ...r,
        lat: 12.9716 + (Math.random() * 0.05 - 0.025), // Mock nearby positions
        lng: 77.5946 + (Math.random() * 0.05 - 0.025),
        status: r.is_active ? 'Active' : 'Idle'
    })) : [
        { id: 1, name: 'John Doe', lat: 12.9716, lng: 77.5946, status: 'Active' },
        { id: 2, name: 'Jane Smith', lat: 12.9720, lng: 77.5950, status: 'Idle' }
    ];

    if (loading) return <div className="flex justify-center items-center h-64"><div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-500"></div></div>;

    const activeExecs = reps.filter(r => r.is_active).length;

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard
                    title="Active Executives"
                    value={`${activeExecs}/${reps.length}`}
                    icon={Users}
                    color="bg-blue-100 text-blue-600"
                    trend="Currently on field"
                />
                <StatCard
                    title="Today's Visits"
                    value="42"
                    icon={CheckCircle2}
                    color="bg-emerald-100 text-emerald-600"
                    trend="↑ 12% from yesterday"
                />
                <StatCard
                    title="Distance Covered"
                    value="128 km"
                    icon={Truck}
                    color="bg-purple-100 text-purple-600"
                    trend="Across all execs"
                />
                <StatCard
                    title="Suspicious Activity"
                    value="2"
                    icon={AlertOctagon}
                    color="bg-rose-100 text-rose-600"
                    trend="Needs review"
                />
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden flex flex-col min-h-[400px]">
                    <div className="p-4 border-b border-gray-200 bg-gray-50">
                        <h2 className="text-lg font-bold text-gray-800 flex items-center">
                            <LocateFixed className="w-5 h-5 mr-2 text-blue-500" />
                            Real-time Executive Locations
                        </h2>
                    </div>
                    <div className="flex-1 w-full relative z-0">
                        <MapContainer
                            center={[12.9716, 77.5946]}
                            zoom={12}
                            style={{ height: '100%', width: '100%', minHeight: '400px' }}
                        >
                            <TileLayer
                                attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                                url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                            />
                            {mapData.map((rep) => (
                                <Marker key={rep.id} position={[rep.lat, rep.lng]}>
                                    <Popup>
                                        <div className="font-semibold text-gray-900">{rep.name}</div>
                                        <div className="text-xs text-gray-600">Status: {rep.status}</div>
                                        <div className="text-xs text-blue-600 mt-1 cursor-pointer">View Details</div>
                                    </Popup>
                                </Marker>
                            ))}
                        </MapContainer>
                    </div>
                </div>

                <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-6 flex flex-col max-h-[500px]">
                    <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center shrink-0">
                        <Users className="w-5 h-5 mr-2 text-gray-500" />
                        Executive Status
                    </h3>
                    <div className="space-y-4 overflow-y-auto pr-2 flex-1">
                        {reps.map(rep => (
                            <RepCard key={rep.id} rep={rep} />
                        ))}
                        {reps.length === 0 && <p className="text-sm text-gray-500 text-center py-8">No marketing reps found.</p>}
                    </div>
                </div>
            </div>
        </div>
    );
};

export default OverviewTab;
