import React, { useState, useEffect } from 'react';
import Layout from './Layout';
import OverviewTab from './OverviewTab';
import TargetManagement from './TargetManagement';
import SalesRecording from './SalesRecording';
import FraudAlerts from './FraudAlerts';
import Analytics from './Analytics';
import UserManagement from './UserManagement';
import Settings from './Settings';
import RepDetails from './RepDetails';
import CustomersManagement from './CustomersManagement';
import OrdersManagement from './OrdersManagement';

const Dashboard = () => {
  const [activeTab, setActiveTab] = useState('overview');

  const renderContent = () => {
    switch (activeTab) {
      case 'overview':
        return <OverviewTab />;
      case 'users':
        return <UserManagement />;
      case 'reps':
        return <RepDetails />;
      case 'targets':
        return <TargetManagement />;
      case 'sales':
        return <SalesRecording />;
      case 'alerts':
        return <FraudAlerts />;
      case 'logs': // Keeping the naming convention from Layout
        return <Analytics />; // Assuming Analytics replaces Visit Logs for now or vice-versa
      case 'customers':
        return <CustomersManagement />;
      case 'orders':
        return <OrdersManagement />;
      case 'settings':
        return <Settings />;
      default:
        return <OverviewTab />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
        {renderContent()}
      </div>
    </Layout>
  );
};

export default Dashboard;
